import React, { useEffect, useState, useCallback } from 'react';
import api from '../../utils/api';
import toast from 'react-hot-toast';

const fmt = (n) => `₹${parseFloat(n||0).toLocaleString('en-IN')}`;

const emptyForm = { 
  name:'', description:'', short_desc:'', category_id:'', brand_id:'', 
  price:'', compare_price:'', cost_price:'', stock:'', sku:'', tags:'', 
  is_featured:false, is_new_arrival:false, is_active:true 
};

export default function AdminProducts() {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [brands, setBrands]     = useState([]);
  const [total, setTotal]       = useState(0);
  const [loading, setLoading]   = useState(true);
  const [page, setPage]         = useState(1);
  const [search, setSearch]     = useState('');
  const [catFilter, setCatFilter] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving]     = useState(false);
  const [editId, setEditId]     = useState(null);
  const [imageUrl, setImageUrl] = useState('');
  const [form, setForm] = useState(emptyForm);

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const q = new URLSearchParams({ page, limit:15 });
      if (search) q.set('search', search);
      if (catFilter) q.set('category', catFilter);
      const r = await api.get(`/products?${q}`);
      setProducts(r.data.products);
      setTotal(r.data.total);
    } catch {} finally { setLoading(false); }
  }, [page, search, catFilter]);

  // ✅ FIXED: removed dependency on fetchProducts
  useEffect(() => {
    fetchProducts();
  }, [page, catFilter]);

  // ✅ debounce search (prevents re-render spam)
  useEffect(() => {
    const delay = setTimeout(() => {
      setPage(1);
      fetchProducts();
    }, 500);

    return () => clearTimeout(delay);
  }, [search]);

  useEffect(() => {
    api.get('/categories').then(r => setCategories(r.data.categories)).catch(()=>{});
    api.get('/brands').then(r => setBrands(r.data.brands)).catch(()=>{});
  }, []);

  const handleSave = async (e) => {
    e.preventDefault();
    if (!form.name || !form.price) { toast.error('Name and price are required.'); return; }
    setSaving(true);
    try {
      const payload = {
        ...form,
        tags: form.tags ? form.tags.split(',').map(t=>t.trim()) : [],
        images: imageUrl ? [{ url: imageUrl, alt: form.name, is_primary: true }] : []
      };

      if (editId) { 
        await api.put(`/products/${editId}`, payload); 
        toast.success('Product updated!'); 
      } else { 
        await api.post('/products', payload); 
        toast.success('Product created!'); 
      }

      setShowForm(false);
      setForm(emptyForm);
      setEditId(null);
      fetchProducts();

    } catch (err) { 
      toast.error(err.response?.data?.message || 'Failed to save.'); 
    } finally { 
      setSaving(false); 
    }
  };

  const handleEdit = (p) => {
    setForm({ 
      ...p, 
      tags: Array.isArray(p.tags) ? p.tags.join(', ') : '', 
      category_id: p.category_id || '', 
      brand_id: p.brand_id || '' 
    });
    setEditId(p.id); 
    setShowForm(true);
    window.scrollTo({ top: 0 });
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Deactivate this product?')) return;
    try { 
      await api.delete(`/products/${id}`); 
      toast.success('Product deactivated.'); 
      fetchProducts(); 
    } catch (err) { 
      toast.error(err.response?.data?.message || 'Failed.'); 
    }
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append("image", file);

    try {
      const res = await fetch("http://localhost:5000/api/upload", {
        method: "POST",
        body: formData
      });

      const data = await res.json();

      if (data.url) {
        setImageUrl(data.url);
        toast.success("Image uploaded successfully ✅");
      } else {
        toast.error("Upload failed ❌");
      }

    } catch {
      toast.error("Upload error ❌");
    }
  };

  const F = ({ label, children }) => (
    <div><label className="form-label">{label}</label>{children}</div>
  );

  return (
    <div className="space-y-5">

      {showForm && (
        <div className="bg-white border p-6">
          <form onSubmit={handleSave}>
            <F label="Product Name *">
              <input
                type="text"
                className="form-input"
                value={form.name}
                onChange={(e)=>setForm(prev=>({...prev,name:e.target.value}))}
              />
            </F>

            <F label="SKU">
              <input
                type="text"
                className="form-input"
                value={form.sku || ''}
                onChange={(e)=>setForm(prev=>({...prev,sku:e.target.value}))}
              />
            </F>

            <button type="submit">Save</button>
          </form>
        </div>
      )}

      <input
        placeholder="Search..."
        value={search}
        onChange={(e)=>setSearch(e.target.value)} // ✅ FIXED
      />

    </div>
  );
}
